 18	function toReceiptStoryId(storyId: string): string {
 19	  const numericPrefix = storyId.match(/^(\d+)/)?.[1];
 20	  if (numericPrefix) {
 21	    return `story-${numericPrefix.padStart(2, "0")}`;
 22	  }
 23	
 24	  return storyId.startsWith("story-") ? storyId : `story-${storyId}`;
 25	}
 26	
 27	function toReceiptTitle(storyId: string): string {
 28	  const titleSource = storyId.replace(/^\d+-/, "");
 29	  const words = titleSource
 30	    .split("-")
 31	    .filter(Boolean)
 32	    .map((word) => word.toLowerCase());
 33	
 34	  return words
 35	    .map((word, index) => {
 36	      if (index > 0 && ["a", "an", "and", "for", "in", "of", "on", "the", "to", "with"].includes(word)) {
 37	        return word;
 38	      }
 39	
 40	      return word.charAt(0).toUpperCase() + word.slice(1);
 41	    })
 42	    .join(" ");
 43	}
 44	
 45	function renderStoryReceiptTemplate(storyIds: string[]): string {
 46	  if (storyIds.length === 0) {
 47	    return "- none yet";
 48	  }
 49	
 50	  const templateStoryId = storyIds[storyIds.length - 1];
 51	
 52	  return [
 53	    `### ${toReceiptStoryId(templateStoryId)}`,
 54	    `- Title: ${toReceiptTitle(templateStoryId)}`,
 55	    "- Implementor Evidence Ref: pending",
 56	    "- Verifier Evidence Refs:",
 57	    "  - pending-primary",
 58	    "  - pending-secondary",
 59	    "- Gate Command: pending",
 60	    "- Gate Result: pending (pass | fail)",
 61	    "- Dispositions:",
 62	    "  - FINDING-ID: fixed | accepted-risk | defer",
 63	    "- Baseline Before Story: pending",
 64	    "- Baseline After Story: pending",
 65	    "- Open Risks:",
 66	    "  - pending",
 67	    "- User Acceptance: pending",
 68	  ].join("\n");
 69	}
 70	
 71	export function renderTeamImplLogTemplate(input: EnsureTeamImplLogInput): string {
 72	  const specPackRoot = resolve(input.specPackRoot);
 73	  const storyLines =
 74	    input.storyIds.length === 0
 75	      ? "- none yet"
 76	      : input.storyIds.map((storyId) => `- ${storyId}`).join("\n");
 77	
 78	  return [
 79	    "# Team Implementation Log",
 80	    "",
 81	    "## Run Overview",
 82	    "- State: SETUP",
 83	    `- Spec Pack Root: ${specPackRoot}`,
 84	    "- Current Story: not-started",
 85	    "- Current Phase: inspect",
 86	    "",
 87	    "## Run Configuration",
 88	    "- Primary Harness: claude-code",
 89	    "- Story Implementor: pending",
 90	    "- Quick Fixer: pending",
 91	    "- Story Verifier 1: pending",
 92	    "- Story Verifier 2: pending",
 93	    "- Self Review Passes: pending",
 94	    "- Degraded Diversity: pending",
 95	    "",
 96	    "## Verification Gates",
 97	    "- Story Gate: pending",
 98	    "- Epic Gate: pending",
 99	    "- Gate Discovery Source: pending",
100	    "",
101	    "## Story Sequence",
102	    storyLines,
103	    "",
104	    "## Current Continuation Handles",
105	    "- none",
106	    "",
107	    "## Story Receipts",
108	    renderStoryReceiptTemplate(input.storyIds),
109	    "",
110	    "## Cumulative Baselines",
111	    "- Baseline Before Current Story: pending",
112	    "- Expected After Current Story: pending",
113	    "- Latest Actual Total: pending",
114	    "",
115	    "## Cleanup / Epic Verification",
116	    "- Cleanup Artifact: pending",
117	    "- Cleanup Status: not-started",
118	    "- Epic Verification Status: not-started",
119	    "",
120	    "## Open Risks / Accepted Risks",
121	    "- none",
122	    "",
123	  ].join("\n");
124	}
125	
126	export async function ensureTeamImplLog(
127	  input: EnsureTeamImplLogInput
128	): Promise<EnsureTeamImplLogResult> {
129	  const path = join(resolve(input.specPackRoot), TEAM_IMPL_LOG_FILE_NAME);
130	
131	  if (await pathExists(path)) {
132	    return {
133	      created: false,
134	      path,
135	      content: await readTextFile(path),
136	    };
137	  }
138	
139	  const content = renderTeamImplLogTemplate(input);
140	  await writeTextFile(path, content);
141	
142	  return {
143	    created: true,
144	    path,
145	    content,
146	  };
147	}

