 34	function renderHumanSummary(envelope: OutputEnvelope) {
 35	  if (
 36	    typeof envelope.result !== "object" ||
 37	    envelope.result === null ||
 38	    !("providerMatrix" in envelope.result)
 39	  ) {
 40	    return `preflight: ${envelope.outcome}`;
